function deleteCronJob(jobId) {
  const task = cronTasks.get(jobId);
  if (task) task.stop();
  cronTasks.delete(jobId);
  const deleted = jobs.delete(jobId);
  if (deleted) persistCronJobs();
  return deleted;
}
