import { Router as Router28 } from "express";
import { v4 as uuid35 } from "uuid";
var mcpGatewayRouter = Router28();
var backendToolsCache = [];
var backendToolsCacheTime = 0;
var CACHE_TTL_MS2 = 3e5;
async function getBackendTools() {
  if (Date.now() - backendToolsCacheTime < CACHE_TTL_MS2 && backendToolsCache.length > 0) {
    return backendToolsCache;
  }
  try {
    const r = await fetch(`${config.backendUrl}/api/mcp/tools`, {
      headers: { Authorization: `Bearer ${config.backendApiKey}` },
      signal: AbortSignal.timeout(1e4)
    });
    if (!r.ok) return backendToolsCache;
    const data = await r.json();
    const rawTools = Array.isArray(data) ? data : Array.isArray(data?.tools) ? data.tools : Array.isArray(data?.data?.tools) ? data.data.tools : [];
    backendToolsCache = rawTools.map((t) => {
      if (typeof t === "string") {
        return {
          name: `backend.${t}`,
          description: `Backend MCP tool: ${t}`,
          inputSchema: { type: "object", properties: { payload: { type: "object", description: "Tool arguments" } } }
        };
      }
      return {
        name: `backend.${t.name ?? t.tool ?? ""}`,
        description: String(t.description ?? `Backend MCP tool: ${t.name ?? t.tool}`),
        inputSchema: t.inputSchema ?? t.input_schema ?? t.parameters ?? { type: "object", properties: {} }
      };
    }).filter((t) => t.name !== "backend.");
    backendToolsCacheTime = Date.now();
    logger.info({ count: backendToolsCache.length }, "MCP gateway: refreshed backend tools cache");
  } catch (err) {
    logger.warn({ err: String(err) }, "MCP gateway: failed to fetch backend tools");
  }
  return backendToolsCache;
}
function getOrchestratorToolsMCP() {
  return toMCPTools();
}
async function handleInitialize(id, params) {
  const clientVersion = params?.protocolVersion ?? "2025-03-26";
  const SUPPORTED_VERSIONS = ["2025-03-26", "2024-11-05"];
  const negotiatedVersion = SUPPORTED_VERSIONS.includes(clientVersion) ? clientVersion : SUPPORTED_VERSIONS[0];
  return {
    jsonrpc: "2.0",
    id,
    result: {
      protocolVersion: negotiatedVersion,
      capabilities: {
        tools: { listChanged: false }
      },
      serverInfo: {
        name: "widgetdc-orchestrator",
        version: "2.1.0"
      }
    }
  };
}
async function handleToolsList(id, params) {
  const orchestratorTools = getOrchestratorToolsMCP();
  const includeBackend = params?.cursor === "include_backend";
  const backendTools = includeBackend ? await getBackendTools() : [];
  return {
    jsonrpc: "2.0",
    id,
    result: {
      tools: [...orchestratorTools, ...backendTools]
    }
  };
}
async function handleToolsCall(id, params) {
  const toolName2 = params.name;
  const args = params.arguments ?? {};
  if (!toolName2) {
    return {
      jsonrpc: "2.0",
      id,
      error: { code: -32602, message: "Missing required parameter: name" }
    };
  }
  const isOrchestratorTool = TOOL_REGISTRY.some((t) => t.name === toolName2);
  if (isOrchestratorTool) {
    try {
      const results = await executeToolCalls([{
        id: uuid35(),
        function: { name: toolName2, arguments: JSON.stringify(args) }
      }]);
      const result = results[0];
      return {
        jsonrpc: "2.0",
        id,
        result: {
          content: [{ type: "text", text: result.content }],
          isError: false
        }
      };
    } catch (err) {
      return {
        jsonrpc: "2.0",
        id,
        result: {
          content: [{ type: "text", text: `Error: ${err}` }],
          isError: true
        }
      };
    }
  }
  const backendName = toolName2.startsWith("backend.") ? toolName2.slice(8) : toolName2;
  try {
    const mcpResult = await callMcpTool({
      toolName: backendName,
      args,
      callId: uuid35(),
      timeoutMs: 3e4
    });
    if (mcpResult.status !== "success") {
      return {
        jsonrpc: "2.0",
        id,
        result: {
          content: [{ type: "text", text: mcpResult.error_message ?? "Tool call failed" }],
          isError: true
        }
      };
    }
    const text = typeof mcpResult.result === "string" ? mcpResult.result : JSON.stringify(mcpResult.result, null, 2);
    return {
      jsonrpc: "2.0",
      id,
      result: {
        content: [{ type: "text", text }],
        isError: false
      }
    };
  } catch (err) {
    return {
      jsonrpc: "2.0",
      id,
      result: {
        content: [{ type: "text", text: `MCP tool error: ${err}` }],
        isError: true
      }
    };
  }
}
async function handlePing(id) {
  return { jsonrpc: "2.0", id, result: {} };
}
mcpGatewayRouter.post("/", async (req, res) => {
  const body = req.body;
  logger.info({ rawBody: JSON.stringify(body).slice(0, 500), contentType: req.headers["content-type"] }, "MCP gateway raw request");
  const method = body?.method ?? "";
  if (!body || !method) {
    res.status(400).json({
      jsonrpc: "2.0",
      id: body?.id ?? null,
      error: { code: -32600, message: `Invalid request \u2014 need at least "method" field. Got: ${JSON.stringify(body).slice(0, 200)}` }
    });
    return;
  }
  const id = body.id ?? null;
  const params = body.params ?? {};
  logger.info({ method, id }, "MCP gateway request");
  let response;
  try {
    switch (method) {
      case "initialize":
        response = await handleInitialize(id ?? null, params);
        break;
      case "notifications/initialized":
        res.status(202).end();
        return;
      case "tools/list":
        response = await handleToolsList(id ?? null, params);
        break;
      case "tools/call":
        response = await handleToolsCall(id ?? null, params ?? {});
        break;
      case "ping":
        response = await handlePing(id ?? null);
        break;
      // Qwen-specific compat: tools/health is non-standard but Qwen's MCP client sends it
      case "tools/health":
        response = {
          jsonrpc: "2.0",
          id: id ?? null,
          result: { status: "healthy", tools_count: getOrchestratorToolsMCP().length }
        };
        break;
      default:
        response = {
          jsonrpc: "2.0",
          id: id ?? null,
          error: { code: -32601, message: `Method not found: ${method}` }
        };
    }
  } catch (err) {
    logger.error({ method, err: String(err) }, "MCP gateway error");
    response = {
      jsonrpc: "2.0",
      id: id ?? null,
      error: { code: -32603, message: `Internal error: ${err}` }
    };
  }
  res.json(response);
});
mcpGatewayRouter.get("/", (req, res) => {
  res.setHeader("Content-Type", "text/event-stream");
  res.setHeader("Cache-Control", "no-cache");
  res.setHeader("Connection", "keep-alive");
  res.write(`event: endpoint
data: /mcp

`);
  const keepAlive = setInterval(() => {
    res.write(": keepalive\n\n");
  }, 3e4);
  req.on("close", () => {
    clearInterval(keepAlive);
  });
});
mcpGatewayRouter.delete("/", (_req, res) => {
  res.status(200).json({ jsonrpc: "2.0", result: { message: "Session terminated" } });
});

