function respondLegacyToolResult(res, result) {
  const httpStatus = result.status === "success" ? 200 : result.status === "timeout" ? 504 : 500;
  res.status(httpStatus).json({
    call_id: result.call_id,
    status: result.status,
    result: result.result,
    error_message: result.error_message ?? null,
    duration_ms: result.duration_ms,
    completed_at: result.completed_at
  });
}
toolGatewayRouter.post("/call", async (req, res) => {
  const toolName2 = typeof req.body?.tool_name === "string" ? req.body.tool_name : null;
  const callId = typeof req.body?.call_id === "string" ? req.body.call_id : uuid36();
  const args = req.body?.arguments && typeof req.body.arguments === "object" ? req.body.arguments : {};
  if (!toolName2) {
    res.status(400).json({
      call_id: callId,
      status: "error",
      result: null,
      error_message: "Legacy /api/tools/call requires tool_name",
      duration_ms: 0,
      completed_at: (/* @__PURE__ */ new Date()).toISOString()
    });
    return;
  }
  logger.warn({ tool: toolName2, call_id: callId }, "Deprecated /api/tools/call shim used");
  const result = await executeToolUnified(toolName2, args, {
    call_id: callId,
    source_protocol: "legacy-rest",
    fold: req.query.fold !== "false"
  });
  if (result.status === "success") {
    recordToolCall(toolName2);
  }
  respondLegacyToolResult(res, result);
});
toolGatewayRouter.post("/:name", async (req, res) => {
  const { name } = req.params;
  const tool = getTool(name);
  if (!tool) {
    res.status(404).json({
      success: false,
      error: {
        code: "TOOL_NOT_FOUND",
        message: `Tool '${name}' not found. Use GET /api/tools to list available tools.`,
        available: TOOL_REGISTRY.map((t) => t.name),
        status_code: 404
      }
    });
    return;
  }
  const callId = req.body?.call_id ?? uuid36();
  const args = req.body ?? {};
  logger.info({ tool: name, call_id: callId }, "REST tool gateway call");
  const result = await executeToolUnified(name, args, {
    call_id: callId,
    source_protocol: "openapi",
    fold: req.query.fold !== "false"
  });
  if (result.status === "success") {
    recordToolCall(name);
  }
  const httpStatus = result.status === "success" ? 200 : result.status === "timeout" ? 504 : 500;
  res.status(httpStatus).json({
    success: result.status === "success",
    data: result
  });
});
toolGatewayRouter.get("/", (_req, res) => {
  const tools = TOOL_REGISTRY.map((t) => ({
    name: t.name,
    namespace: t.namespace,
    category: t.category,
    description: t.description,
    tags: t.tags,
    available_via: t.availableVia,
    timeout_ms: t.timeoutMs,
    endpoint: `/api/tools/${t.name}`
  }));
  res.json({
    success: true,
    data: {
      tools,
      total: tools.length,
      registry_version: "1.0.0"
    }
  });
});

