async function boot() {
  const { validateOrThrow: validateOrThrow2 } = await Promise.resolve().then(() => (init_startup_validator(), startup_validator_exports));
  await validateOrThrow2();
  await initRedis();
  await AgentRegistry.hydrate();
  seedAgents();
  Promise.resolve().then(() => (init_skill_forge(), skill_forge_exports)).then((m) => m.loadForgedTools()).catch(() => {
  });
  await hydrateMessages();
  await hydrateCronJobs();
  registerDefaultLoops();
  await initAnomalyWatcher();
  await initPheromoneLayer();
  await initPeerEval();
  loadBenchmarkRuns().catch((err) => {
    logger.warn({ err: String(err) }, "Benchmark run hydration failed (non-critical)");
  });
  bootKickstartOverdueJobs().catch((err) => {
    logger.warn({ err: String(err) }, "Cron boot-kickstart encountered error");
  });
  initOpenClaw();
  logger.info("WidgeTDC Orchestrator boot complete");
}
boot().catch((err) => {
  logger.error({ err: String(err) }, "Boot failed");
  process.exit(1);
});
